public class HomeFragment extends Fragment {
    private FragmentHomeBinding binding;
    private OkHttpClient client = new OkHttpClient();
    public static boolean isTripActive = false; // Stato iniziale: nessun tragitto attivo
    private Speedometer speedometer; // Dichiarazione dell'oggetto Speedometer
    private TextView speedTextView; // Riferimento al TextView della velocità
    private double co2gKM;

    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, ViewGroup container, Bundle savedInstanceState) {
        binding = FragmentHomeBinding.inflate(inflater, container, false);
        View root = binding.getRoot();
        SharedPreferences sharedPreferences = requireActivity().getSharedPreferences("EcoDrivingPrefs", Context.MODE_PRIVATE);
        co2gKM=sharedPreferences.getFloat("co2_emission", 0.0f);  // 0.0f è il valore di default se non trovato

        // Inizializza i TextView per la velocità e la posizione
        speedTextView = root.findViewById(R.id.speedTextView); // Assicurati che l'ID sia corretto
        //locationTextView = root.findViewById(R.id.locationTextView); // Assicurati che l'ID sia corretto

        // Creazione dell'oggetto Speedometer passando contesto, attività e TextViews

        speedometer = Speedometer.getInstance(requireContext(), requireActivity(), speedTextView);


        // Carica i tragitti al caricamento del frammento
        loadDailyTrips();
        loadDailyCO2();
        loadCo2gKM();
        // Imposta il listener per il click del pulsante
        binding.buttonStartTrip.setOnClickListener(v -> handleButtonClick());

        // Avvia il calcolo della velocità
        speedometer.start();

        return root;
    }

    private void handleButtonClick() {
        if (isTripActive) {
            endTrip(); // Termina il tragitto
        } else {
            startTrip(); // Avvia il tragitto
        }
    }

    private void startTrip() {
        isTripActive = true;
        speedometer.resetTotalDistance();
        if(speedometer.getLoaded()==false){
            speedTextView.setText("Loading...");
        }

        // Cambia l'icona del pulsante per indicare che il tragitto è attivo
        binding.buttonStartTrip.setImageResource(R.drawable.ic_stop_trip); // Modifica l'icona a "stop"
        Toast.makeText(getActivity(), "Tragitto avviato!", Toast.LENGTH_SHORT).show(); // Messaggio di avvio
    }

    private void endTrip() {
        speedometer.setLoaded(false);
        speedTextView.setText("Avvia il tragitto");
        isTripActive = false;

        // Cambia l'icona del pulsante per indicare che il tragitto è terminato
        binding.buttonStartTrip.setImageResource(R.drawable.ic_start_trip);

        saveTripToDatabase(); // This will handle the refresh after successful save
        Toast.makeText(getActivity(), "Tragitto terminato!", Toast.LENGTH_SHORT).show();
    }

    private void loadDailyCO2() {
        SharedPreferences sharedPreferences = requireActivity().getSharedPreferences("EcoDrivingPrefs", Context.MODE_PRIVATE);
        String userId = sharedPreferences.getString("user_id", null);

        if (userId == null) {
            Toast.makeText(getActivity(), "Errore: utente non loggato", Toast.LENGTH_SHORT).show();
            return;
        }

        String currentDate = new SimpleDateFormat("yyyy-MM-dd", Locale.getDefault()).format(new Date());

        JSONObject postData = new JSONObject();
        try {
            postData.put("user_id", userId);
            postData.put("date", currentDate);
        } catch (JSONException e) {
            e.printStackTrace();
        }

        new Thread(() -> {
            MediaType JSON = MediaType.parse("application/json; charset=utf-8");
            RequestBody body = RequestBody.create(postData.toString(), JSON);
            Request request = new Request.Builder()
                    .url("http://"+ip+":8081/api/getDailyCO2")
                    .post(body)
                    .build();

            try (Response response = client.newCall(request).execute()) {
                if (response.isSuccessful()) {
                    String responseData = response.body().string();
                    JSONObject jsonResponse = new JSONObject(responseData);
                    double totalCO2 = jsonResponse.getDouble("total_co2");
                    getActivity().runOnUiThread(() -> updateCO2Display(totalCO2));
                } else {
                    getActivity().runOnUiThread(() ->
                            Toast.makeText(getActivity(), "Errore durante il caricamento delle emissioni", Toast.LENGTH_SHORT).show());
                }
            } catch (IOException | JSONException e) {
                e.printStackTrace();
                getActivity().runOnUiThread(() ->
                        Toast.makeText(getActivity(), "Errore di connessione", Toast.LENGTH_SHORT).show());
            }
        }).start();
    }

    private void updateCO2Display(double totalCO2) {
        TextView tvCO2Display = binding.textTotalCo2; // Assicurati che l'ID sia corretto
        tvCO2Display.setText(String.format(Locale.getDefault(), "CO2 Totale Oggi: %.2f kg", totalCO2));
    }

